import _pickle as cPickle
import base64

def confirmAuth(headers):
    token_str = headers.get('AuthToken', '')
    try:
        decoded = base64.b64decode(token_str)
        token = cPickle.loads(decoded)
        if hasattr(token, 'valid') and token.valid:
            return token.data
        else:
            return None
    except (base64.binascii.Error, cPickle.UnpicklingError, EOFError, AttributeError) as e:
        return None

from flask import Flask, request, jsonify
import yaml

app = Flask(__name__)

@app.route('/yaml')
def yaml_load():
    try:
        yaml_data = request.data
        parsed = yaml.safe_load(yaml_data)
        return jsonify(parsed)
    except yaml.YAMLError as e:
        return jsonify(error=str(e)), 400
    except Exception as e:
        return jsonify(error=str(e)), 500
